import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  it.todo("should return empty grid for empty input");

  it.todo("should kill a single live cell with 0 neighbors -- [(0,0)] → []");

  it.todo("should kill live cells with 1 neighbor (underpopulation) -- [(0,1),(1,1)] → []");

  it.todo("should keep a 2×2 block unchanged (each cell has 2 neighbors, survival) -- [(0,0),(1,0),(0,1),(1,1)] → same");

  it.todo("should let cell with 3 neighbors survive -- cell (1,1) surrounded by 3 lives on");

  it.todo("should kill cell with 4 neighbors (overpopulation) -- cell (1,1) with 4 neighbors dies");

  it.todo("should kill cell with more than 4 neighbors (overpopulation) -- cell with 5+ neighbors dies");

  it.todo("should bring dead cell with exactly 3 neighbors to life (reproduction) -- dead (1,1) with 3 neighbors becomes alive");

  it.todo("should keep dead cell with 2 neighbors dead -- dead (1,1) with 2 neighbors stays dead");

  it.todo("should keep dead cell with 4 neighbors dead -- dead (1,1) with 4 neighbors stays dead");

  it.todo("should evolve blinker Gen 0 to Gen 1 -- [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");

  it.todo("should evolve blinker Gen 1 to Gen 2 -- [(-1,1),(0,1),(1,1)] → [(0,0),(0,1),(0,2)]");
});

export type Cell = [number, number];

export function nextGeneration(_cells: Cell[]): Cell[] {
  return [];
}

